UPDATE product_skus SET on_hand_quantity = on_hand_quantity - #{quantity},
    reserved_quantity = reserved_quantity - #{quantity}, version = version + 1
WHERE id = #{skuId} AND reserved_quantity >= #{quantity} AND on_hand_quantity >= #{quantity}

mapper.select:
SELECT  FROM commerce_orders o
LEFT JOIN shipments sh ON sh.order_id = o.id
WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.created_at DESC, o.id DESC LIMIT #{size} OFFSET #{offset}

SELECT r.id, r.product_id, r.order_item_id, r.user_id, r.rating, r.content,
       u.nickname AS reviewer_name, r.created_at
FROM commerce_product_reviews r JOIN users u ON u.id = r.user_id
WHERE r.product_id = #{productId}
ORDER BY r.created_at DESC, r.id DESC LIMIT #{size} OFFSET #{offset}
